export const getListSuperadminTripHistoryUrl = (params?: ListSuperadminTripHistoryParams,) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {

    if (value !== undefined) {
      normalizedParams.append(key, value === null ? 'null' : value.toString())
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0 ? `/api/superadmin/trip-history?${stringifiedParams}` : `/api/superadmin/trip-history`
}

